136→// Create workspace
137→app.post("/workspaces", async (c) => {
138→  const db = getDatabase();
139→  const { repository_id } = parseBody(CreateWorkspaceBody, await c.req.json());
140→
141→  const repo = getRepositoryById(db, repository_id);
142→  if (!repo) throw new NotFoundError("Repository not found");
143→
144→  const workspace_name = generateUniqueName(db);
145→  const parent_branch = repo.git_default_branch || "main";
146→  const workspaceId = uuidv7();
147→
148→  let branchPrefix = "workspace";
149→  try {
150→    const gitUser = execSync("git config user.name", { cwd: repo.root_path!, encoding: "utf8" })
151→      .trim()
152→      .toLowerCase()
153→      .replace(/[^a-z0-9_-]/g, "-");
154→    if (gitUser) branchPrefix = gitUser;
155→  } catch {}
156→  const placeholderBranchName = `${branchPrefix}/${workspace_name}`;
157→
158→  // ─── IMPORTANT: Remote-first branch strategy ───────────────────────
159→  // We ALWAYS want worktrees branched from origin/<parent_branch>, not
160→  // local <parent_branch>. Diffs are computed against origin/<branch>
161→  // (see resolve_parent_branch in git.rs and git.service.ts). If origin
162→  // is stale, the merge-base drifts and every file since the divergence
163→  // shows as "changed" — producing hundreds of phantom file changes.
164→  //
165→  // Fetch the remote branch before creating the worktree so that:
166→  // 1. The worktree starts from the latest upstream commit
167→  // 2. Diff merge-base matches what we branched from (zero phantom changes)
168→  // 3. PRs will be clean against the upstream target
169→  //
170→  // This is a non-blocking fetch (~1-3s on a warm connection). Workspace
171→  // creation is already async (worktree add runs in a child process) and
172→  // correctness matters more here.
173→  // ───────────────────────────────────────────────────────────────────
174→  try {
175→    await execFileAsync("git", ["fetch", "origin", parent_branch], {
176→      cwd: repo.root_path!,
177→      timeout: 15000,
178→    });
179→  } catch (fetchErr) {
180→    // Non-fatal: if fetch fails (offline, no remote, etc.), fall back to
181→    // whatever local state we have. The worktree will still be created
182→    // from the local branch — diffs might be off but it's better than
183→    // blocking workspace creation entirely.
184→    console.warn(
185→      `[WORKSPACE] git fetch origin ${parent_branch} failed (continuing with local):`,
186→      fetchErr
187→    );
188→  }
189→
190→  db.prepare(
191→    `
192→    INSERT INTO workspaces (
193→      id, repository_id, slug, git_branch,
194→      git_target_branch, state, updated_at
195→    ) VALUES (?, ?, ?, ?, ?, ?, datetime('now'))
196→  `
197→  ).run(
198→    workspaceId,
199→    repository_id,
200→    workspace_name,
201→    placeholderBranchName,
202→    parent_branch,
203→    "initializing"
204→  );
205→
206→  // Branch from origin/<parent_branch> when available (fetched above).
207→  // Falls back to local <parent_branch> if remote doesn't exist.
208→  const worktreeBase = await (async () => {
209→    try {
210→      await execFileAsync(
211→        "git",
212→        ["show-ref", "--verify", "--quiet", `refs/remotes/origin/${parent_branch}`],
213→        {
214→          cwd: repo.root_path!,
215→          timeout: 2000,
216→        }
217→      );
218→      return `origin/${parent_branch}`;
219→    } catch {
220→      return parent_branch;
221→    }
222→  })();
223→
224→  const workspacePath = path.join(repo.root_path!, ".opendevs", workspace_name);
225→
226→  // Fire-and-forget: run the init pipeline async (don't await).
227→  // Pipeline handles: worktree creation → deps install → .env copy → session creation.
228→  // Progress events flow: stdout → Electron main process → IPC events → Frontend.
229→  // On fatal failure: reverse cleanup (rm dir, prune worktree, delete branch).
230→  initializeWorkspace({
231→    workspaceId,
232→    repositoryId: repository_id,
233→    repoRootPath: repo.root_path!,
234→    workspacePath,
235→    branchName: placeholderBranchName,
236→    worktreeBase,
237→    parentBranch: parent_branch,
238→  })
239→    .then(() => {
240→      // Workspace is ready — check for manifest setup script
241→      const manifest = readManifestWithFallback(workspacePath, repo.root_path!);
242→      const setupCmd = manifest ? getSetupCommand(manifest) : null;
243→      if (setupCmd && manifest) {
244→        db.prepare("UPDATE workspaces SET setup_status = 'running' WHERE id = ?").run(workspaceId);
245→        const setupEnv = getOpenDevsEnv(manifest, {
246→          id: workspaceId,
247→          rootPath: repo.root_path!,
248→          workspacePath,
249→        });
250→        runSetupScript(db, workspaceId, setupCmd, setupEnv, workspacePath);
251→      }
252→    })
253→    .catch((err) => {
254→      // Belt-and-suspenders: initializeWorkspace handles its own errors,
255→      // but if something truly unexpected escapes, don't leave workspace stuck.
256→      console.error("[WORKSPACE] Unhandled init pipeline error:", err);
257→      try {
258→        db.prepare(
259→          "UPDATE workspaces SET state = 'error', init_stage = 'unhandled', error_message = 'Unhandled init pipeline error' WHERE id = ? AND state = 'initializing'"
260→        ).run(workspaceId);
261→        invalidate(["workspaces", "stats"]);
262→      } catch {}
263→    });
264→
265→  const workspace = getWorkspaceForMiddleware(db, workspaceId);
266→  if (!workspace) throw new NotFoundError("Workspace not found after creation");
267→
268→  // Push immediately so clients see the workspace in 'initializing' state.
269→  // Query-protocol subscribers get snapshots + q:invalidate for unmounted caches.
270→  // The init pipeline will invalidate again when it transitions to 'ready'.
271→  invalidate(["workspaces", "stats"]);
272→
273→  return c.json({ ...workspace, workspace_path: computeWorkspacePath(workspace) });
274→});
