329→app.post("/workspaces/:id/retry-setup", withWorkspace, (c) => {
330→  const db = getDatabase();
331→  const workspace = c.get("workspace");
332→  const workspacePath = c.get("workspacePath");
333→
334→  if (workspace.setup_status !== "failed") {
