336→  }
337→
338→  if (!workspace.root_path) {
339→    throw new ValidationError("Repository path not found");
340→  }
341→
342→  // Re-read manifest (AI agent may have fixed it, or it was added to repo root via settings)
343→  const manifest = readManifestWithFallback(workspacePath, workspace.root_path);
344→  const setupCmd = manifest ? getSetupCommand(manifest) : null;
345→  if (!setupCmd || !manifest) {
346→    db.prepare(
347→      "UPDATE workspaces SET setup_status = 'none', error_message = NULL, updated_at = datetime('now') WHERE id = ?"
348→    ).run(workspace.id);
349→    return c.json({ setup_status: "none" });
350→  }
351→
352→  db.prepare(
353→    "UPDATE workspaces SET setup_status = 'running', error_message = NULL, updated_at = datetime('now') WHERE id = ?"
354→  ).run(workspace.id);
355→
356→  const setupEnv = getOpenDevsEnv(manifest, {
357→    id: workspace.id,
358→    rootPath: workspace.root_path,
359→    workspacePath,
360→  });
361→  runSetupScript(db, workspace.id, setupCmd, setupEnv, workspacePath);
362→
363→  return c.json({ setup_status: "running" });
364→});
