396→  const ptyId = `task-${workspace.id}-${taskName}-${Date.now()}`;
397→  const env = {
398→    ...(manifest.env ?? {}),
399→    ...task.env,
400→    OPENDEVS_ROOT_PATH: workspace.root_path,
401→    OPENDEVS_WORKSPACE_PATH: workspacePath,
402→    OPENDEVS_WORKSPACE_ID: workspace.id,
403→  };
404→
405→  return c.json({
406→    ptyId,
407→    command: task.command,
408→    cwd: workspacePath,
409→    env,
410→    persistent: task.persistent,
411→    mode: task.mode,
412→  });
413→});
