103→/**
104→ * Derive display status from workspace data
105→ *
106→ * Priority logic:
107→ * 1. Error — session in error state
108→ * 2. Unread — agent needs user response (needs_response / needs_plan_response)
109→ * 3. Working — agent actively processing
110→ * 4. Idle — dormant
111→ *
112→ * @param workspace Workspace data with session info
113→ * @returns Derived display status for UI rendering
114→ */
115→export function getDisplayStatus(workspace: Workspace): DisplayStatus {
116→  const status = workspace.session_status;
117→
118→  if (status === "error") return "error";
119→  if (status === "needs_response" || status === "needs_plan_response") return "unread";
120→  if (status === "working") return "working";
121→  return "idle";
122→}
123→
124→/**
125→ * Check if workspace needs user attention.
126→ * In V2, attention state is derived from session_status (needs_response / needs_plan_response).
127→ */
128→export function getUnreadCount(workspace: Workspace): number {
129→  const status = workspace.session_status;
130→  return status === "needs_response" || status === "needs_plan_response" ? 1 : 0;
131→}
132→
133→/**
134→ * Sort workspaces by status priority
135→ * Higher priority statuses appear first
136→ *
137→ * @param workspaces Array of workspaces to sort
138→ * @returns Sorted array (original array not mutated)
139→ */
140→export function sortByStatusPriority<T extends Workspace>(workspaces: T[]): T[] {
141→  return [...workspaces].sort((a, b) => {
142→    const statusA = getDisplayStatus(a);
143→    const statusB = getDisplayStatus(b);
144→    const priorityA = STATUS_CONFIG[statusA].priority;
145→    const priorityB = STATUS_CONFIG[statusB].priority;
146→
147→    // Higher priority first
148→    if (priorityA !== priorityB) {
149→      return priorityB - priorityA;
150→    }
151→
152→    // Same priority: sort by latest activity (most recent first)
153→    const timeA = new Date(a.updated_at).getTime();
154→    const timeB = new Date(b.updated_at).getTime();
155→    return timeB - timeA;
156→  });
157→}
158→
159→/**
160→ * Group workspaces by display status
161→ * Used for rendering section headers in expanded sidebar
162→ *
163→ * @param workspaces Array of workspaces to group
164→ * @returns Object with status as keys, workspace arrays as values
165→ */
166→export function groupByStatus<T extends Workspace>(
167→  workspaces: T[]
168→): Partial<Record<DisplayStatus, T[]>> {
169→  const groups: Partial<Record<DisplayStatus, T[]>> = {};
170→
171→  workspaces.forEach((workspace) => {
172→    const status = getDisplayStatus(workspace);
173→    if (!groups[status]) {
174→      groups[status] = [];
175→    }
176→    groups[status]!.push(workspace);
177→  });
178→
179→  return groups;
180→}
