182→/**
183→ * Get aggregate status counts for a repository
184→ * Used for collapsed sidebar status indicators
185→ *
186→ * @param workspaces Workspaces in a repository
187→ * @returns Count of each status type
188→ */
189→export function getStatusCounts(workspaces: Workspace[]): Record<DisplayStatus, number> {
190→  const counts: Record<DisplayStatus, number> = {
191→    error: 0,
192→    unread: 0,
193→    working: 0,
194→    idle: 0,
195→  };
196→
197→  workspaces.forEach((workspace) => {
198→    const status = getDisplayStatus(workspace);
199→    counts[status]++;
200→  });
201→
202→  return counts;
203→}
