215→/**
216→ * Get highest priority status for a repository
217→ * Used for collapsed sidebar badge color
218→ *
219→ * @param workspaces Workspaces in a repository
220→ * @returns The highest priority status present
221→ */
222→export function getRepoPriorityStatus(workspaces: Workspace[]): DisplayStatus {
223→  let highestPriority = StatusPriority.IDLE;
224→  let highestStatus: DisplayStatus = "idle";
225→
226→  workspaces.forEach((workspace) => {
227→    const status = getDisplayStatus(workspace);
228→    const priority = STATUS_CONFIG[status].priority;
229→
230→    if (priority > highestPriority) {
231→      highestPriority = priority;
232→      highestStatus = status;
233→    }
234→  });
235→
236→  return highestStatus;
237→}
