195→    },
196→    enabled: !!workspaceId && workspaceState === "ready",
197→    staleTime: 30000,
198→    // Events handle invalidation when watched; fall back to polling otherwise
199→    refetchInterval: isWatched ? false : sessionStatus === "working" ? 5000 : false,
200→    refetchOnMount: "always",
201→    refetchOnWindowFocus: true,
202→  });
