378→/**
379→ * Archive workspace mutation with optimistic update
380→ *
381→ * Flow:
382→ * 1. User clicks archive → UI updates IMMEDIATELY (workspace removed from list)
383→ * 2. HTTP request sent in background
384→ * 3. Success: Cache already correct, refetch confirms
385→ * 4. Error: Rollback to previous state, show error
386→ */
387→export function useArchiveWorkspace() {
388→  const queryClient = useQueryClient();
389→  const queryKey = queryKeys.workspaces.byRepo("ready,initializing");
390→
391→  return useMutation({
392→    mutationFn: (workspaceId: string) => WorkspaceService.archive(workspaceId),
393→
394→    // Optimistic update: Remove workspace from UI immediately
395→    onMutate: async (workspaceId: string) => {
396→      // Cancel any outgoing refetches (so they don't overwrite our optimistic update)
397→      await queryClient.cancelQueries({ queryKey });
398→
399→      // Snapshot the previous value
400→      const previousData = queryClient.getQueryData<RepoGroup[]>(queryKey);
401→
402→      // Optimistically remove the workspace from the list
403→      queryClient.setQueryData<RepoGroup[]>(queryKey, (old) => {
404→        if (!old) return old;
405→        return produce(old, (draft) => {
406→          for (const repo of draft) {
407→            const index = repo.workspaces.findIndex((w) => w.id === workspaceId);
408→            if (index !== -1) {
409→              repo.workspaces.splice(index, 1);
410→              break;
411→            }
412→          }
413→        });
414→      });
415→
416→      // Return context with the previous value for rollback
417→      return { previousData };
418→    },
419→
420→    // If mutation fails, roll back to the previous value
421→    onError: (_err, _workspaceId, context) => {
422→      if (context?.previousData) {
423→        queryClient.setQueryData(queryKey, context.previousData);
424→      }
425→    },
426→
427→    onSuccess: (_data, workspaceId) => {
428→      track("workspace_archived", { workspace_id: workspaceId });
429→    },
430→
431→    // Always refetch after error or success to ensure consistency
432→    onSettled: () => {
433→      queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
434→    },
435→  });
436→}
437→
438→/**
439→ * Unarchive workspace mutation — restores state to "ready".
440→ * Used by the undo toast after archiving.
441→ */
442→export function useUnarchiveWorkspace() {
443→  const queryClient = useQueryClient();
444→
445→  return useMutation({
446→    mutationFn: (workspaceId: string) => WorkspaceService.update(workspaceId, { state: "ready" }),
447→    onSuccess: (_data, workspaceId) => {
448→      track("workspace_unarchived", { workspace_id: workspaceId });
449→    },
450→    onSettled: () => {
451→      queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
452→    },
453→  });
454→}
455→
456→/**
457→ * Fetch system prompt for a workspace
458→ */
459→export function useSystemPrompt(workspaceId: string | null) {
460→  return useQuery({
461→    queryKey: queryKeys.workspaces.systemPrompt(workspaceId || ""),
462→    queryFn: async () => {
463→      const result = await WorkspaceService.fetchSystemPrompt(workspaceId!);
464→      return result.system_prompt || "";
465→    },
466→    enabled: !!workspaceId,
467→    staleTime: 30000, // System prompts don't change often
468→  });
469→}
470→
471→/**
472→ * Update system prompt mutation with optimistic update
473→ */
474→export function useUpdateSystemPrompt() {
475→  const queryClient = useQueryClient();
476→
477→  return useMutation({
478→    mutationFn: ({ workspaceId, systemPrompt }: { workspaceId: string; systemPrompt: string }) =>
479→      WorkspaceService.updateSystemPrompt(workspaceId, systemPrompt),
480→
481→    // Optimistic update: Show new prompt immediately
482→    onMutate: async ({ workspaceId, systemPrompt }) => {
483→      await queryClient.cancelQueries({
484→        queryKey: queryKeys.workspaces.systemPrompt(workspaceId),
485→      });
486→
487→      const previousPrompt = queryClient.getQueryData<string>(
488→        queryKeys.workspaces.systemPrompt(workspaceId)
489→      );
490→
491→      queryClient.setQueryData(queryKeys.workspaces.systemPrompt(workspaceId), systemPrompt);
492→
493→      return { previousPrompt };
494→    },
495→
496→    onError: (_err, variables, context) => {
497→      if (context?.previousPrompt !== undefined) {
498→        queryClient.setQueryData(
499→          queryKeys.workspaces.systemPrompt(variables.workspaceId),
500→          context.previousPrompt
501→        );
502→      }
503→    },
504→
505→    onSettled: (_, __, variables) => {
506→      queryClient.invalidateQueries({
507→        queryKey: queryKeys.workspaces.systemPrompt(variables.workspaceId),
508→      });
509→    },
510→  });
511→}
512→
513→/**
514→ * Fetch opendevs.json manifest + normalized tasks for a workspace.
515→ * Manifest doesn't change during a session — staleTime: Infinity.
516→ */
517→export function useManifestTasks(workspaceId: string | null) {
518→  return useQuery({
519→    queryKey: queryKeys.workspaces.manifest(workspaceId || ""),
520→    queryFn: () => WorkspaceService.fetchManifest(workspaceId!),
521→    enabled: !!workspaceId,
522→    staleTime: Infinity,
523→  });
524→}
525→
526→/**
527→ * Retry failed setup for a workspace.
528→ * Invalidates workspace queries to refresh setup_status.
529→ */
530→export function useRetrySetup() {
531→  const queryClient = useQueryClient();
532→
533→  return useMutation({
534→    mutationFn: (workspaceId: string) => WorkspaceService.retrySetup(workspaceId),
535→    onSettled: () => {
536→      queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
537→    },
538→  });
539→}
