 47→app.get("/workspaces/by-repo", (c) => {
 48→  const db = getDatabase();
 49→  const stateParam = c.req.query("state");
 50→  const workspaces = getWorkspacesByRepo(db, stateParam);
 51→
 52→  const grouped: Record<string, any> = {};
 53→  workspaces.forEach((workspace) => {
 54→    const repoId = workspace.repository_id || "unknown";
 55→    if (!grouped[repoId]) {
 56→      grouped[repoId] = {
 57→        repo_id: repoId,
 58→        repo_name: workspace.repo_name || "Unknown",
 59→        sort_order: workspace.repo_sort_order || 999,
 60→        workspaces: [],
 61→      };
 62→    }
 63→    grouped[repoId].workspaces.push({
 64→      ...workspace,
 65→      workspace_path: computeWorkspacePath(workspace),
 66→    });
 67→  });
 68→
 69→  // Backfill repos that have no matching workspaces (e.g. all archived)
 70→  // so they still appear in the sidebar.
 71→  const allRepos = getAllRepositorySummaries(db);
 72→  for (const repo of allRepos) {
 73→    if (!grouped[repo.id]) {
 74→      grouped[repo.id] = {
 75→        repo_id: repo.id,
 76→        repo_name: repo.name,
 77→        sort_order: repo.sort_order ?? 999,
 78→        workspaces: [],
 79→      };
 80→    }
 81→  }
 82→
 83→  const result = Object.values(grouped).sort((a: any, b: any) => a.sort_order - b.sort_order);
 84→  return c.json(result);
 85→});
 86→
 87→app.get("/workspaces/:id", (c) => {
