  1→// backend/src/services/query-engine.ts
  2→// Query engine — handles q:* protocol frames for typed reactive queries.
  3→// Module singleton: subscription state + dispatch logic.
  4→// Works for both local WS and relay-tunneled connections via WsSendable.
  5→//
  6→// Subscription model: ID-keyed. Client assigns IDs ("sub_1", "sub_2") and
  7→// server echoes them back on q:snapshot/q:delta so the client can route
  8→// to the correct callback.
  9→
 10→import { match } from "ts-pattern";
 11→import { getDatabase } from "../lib/database";
 12→import {
 13→  getDashboardWorkspaces,
 14→  getStats,
 15→  getSessionsByWorkspaceId,
 16→  getSessionById,
 17→  getMessages,
 18→  hasOlderMessages,
 19→  hasNewerMessages,
 20→  getWorkspaceRaw,
 21→  getMaxMessageSeq,
 22→  getMessagesDelta,
 23→  resetStatsCache,
 24→  getWorkspacesByRepo,
 25→  getWorkspacesBySessionIds,
 26→  getAllRepositorySummaries,
 27→} from "../db";
 28→import { computeWorkspacePath } from "../middleware/workspace-loader";
 29→import { getConnection } from "./ws.service";
 30→import { resolveToolRelay, rejectToolRelay, runCommand } from "./agent";
 31→import {
 32→  QUERY_RESOURCES,
 33→  MUTATION_NAMES,
 34→  COMMAND_NAMES,
 35→  type MutationName,
 36→  type CommandName,
 37→  type QueryResource,
 38→  type QServerFrame,
 39→} from "@shared/types/query-protocol";
 40→
 41→// ---- Subscription State ----
 42→
 43→type QueryParams = Record<string, unknown>;
 44→
 45→interface ResourceFrameInput {
 46→  id: string;
 47→  resource: string;
 48→  params: QueryParams;
 49→}
 50→
 51→interface UnsubscribeFrameInput {
 52→  id: string;
 53→}
 54→
 55→interface MutateFrameInput {
 56→  id: string;
 57→  action: string;
 58→  params: QueryParams;
 59→}
 60→
 61→interface CommandFrameInput {
 62→  id: string;
 63→  command: string;
 64→  params: QueryParams;
 65→}
 66→
 67→interface Sub {
 68→  id: string;
 69→  resource: QueryResource;
 70→  params: QueryParams;
 71→}
 72→
 73→/** Per-connection active subscriptions, keyed by client-assigned sub ID. */
 74→const subs = new Map<string, Map<string, Sub>>();
 75→
 76→/** For messages: track last seen seq per subscription for delta push.
 77→ *  Key: `${connectionId}:${subId}` → lastSeq */
 78→const messageCursors = new Map<string, number>();
 79→
 80→// ---- Public API ----
 81→
 82→/**
 83→ * Handle an incoming q:* frame from an authenticated connection.
 84→ * Registered as onQueryFrame in ws.service protocol handlers.
 85→ */
 86→export function handleFrame(connectionId: string, msg: QueryParams): void {
 87→  const type = typeof msg.type === "string" ? msg.type : "unknown";
 88→
 89→  try {
 90→    match(type)
 91→      .with("q:request", () => {
 92→        handleRequest(connectionId, parseResourceFrame(msg));
 93→      })
 94→      .with("q:subscribe", () => {
 95→        handleSubscribe(connectionId, parseResourceFrame(msg));
 96→      })
 97→      .with("q:unsubscribe", () => {
 98→        handleUnsubscribe(connectionId, parseUnsubscribeFrame(msg));
 99→      })
100→      .with("q:mutate", () => {
101→        handleMutate(connectionId, parseMutateFrame(msg));
102→      })
103→      .with("q:command", () => {
104→        handleCommand(connectionId, parseCommandFrame(msg));
105→      })
106→      .with("q:tool_response", () => {
107→        handleToolResponse(msg);
108→      })
109→      .otherwise(() => {
110→        sendFrame(connectionId, {
111→          type: "q:error",
112→          id: getFrameId(msg),
113→          code: "UNKNOWN_FRAME",
114→          message: `Unknown query frame type: ${type}`,
115→        });
116→      });
117→  } catch (err) {
118→    sendFrame(connectionId, {
119→      type: "q:error",
120→      id: getFrameId(msg),
121→      code: "INVALID_FRAME",
122→      message: err instanceof Error ? err.message : "Invalid query frame",
123→    });
124→  }
125→}
126→
127→/** Remove all subscriptions for a connection (cleanup on disconnect). */
128→export function removeSubs(connectionId: string): void {
129→  const connSubs = subs.get(connectionId);
130→  if (connSubs) {
131→    for (const [subId, sub] of connSubs) {
132→      if (sub.resource === "messages") {
133→        messageCursors.delete(`${connectionId}:${subId}`);
134→      }
135→    }
136→    subs.delete(connectionId);
137→  }
138→}
139→
140→/** Optional context for targeted invalidation (e.g., which sessions changed). */
141→interface InvalidateContext {
142→  sessionIds?: string[];
143→}
144→
145→/**
146→ * Push-first invalidation: re-run queries for active subscribers and push
147→ * fresh snapshots or deltas.
148→ *
149→ * Messages use q:delta (cursor-based) instead of full snapshots.
150→ * When `ctx.sessionIds` is provided, workspace subscribers receive a targeted
151→ * q:delta (only the changed workspaces) instead of a full q:snapshot.
152→ */
153→export function invalidate(resources: QueryResource[], ctx?: InvalidateContext): void {
154→  if (resources.includes("stats")) {
155→    resetStatsCache();
156→  }
157→
158→  // Phase 1: Push fresh data to active subscribers
159→  for (const [connectionId, connSubs] of subs) {
160→    if (!getConnection(connectionId)) {
161→      removeSubs(connectionId);
162→      continue;
163→    }
164→
165→    for (const [subId, sub] of connSubs) {
166→      if (!resources.includes(sub.resource)) continue;
167→
168→      if (sub.resource === "messages") {
169→        // Messages: push delta (new messages since last cursor)
170→        pushMessageDelta(connectionId, subId, sub.params);
171→      } else if (sub.resource === "workspaces" && ctx?.sessionIds?.length) {
172→        // Workspaces with session context: try targeted delta
173→        try {
174→          const db = getDatabase();
175→          const stateFilter = readStringParam(sub.params, "state") ?? "ready,initializing";
176→          const allowedStates = new Set(stateFilter.split(",").map((s) => s.trim()));
177→          const changedWorkspaces = getWorkspacesBySessionIds(db, ctx.sessionIds).filter((ws) =>
178→            allowedStates.has(ws.state)
179→          );
180→          if (changedWorkspaces.length > 0) {
181→            const withPaths = changedWorkspaces.map((ws) => ({
182→              ...ws,
183→              workspace_path: computeWorkspacePath(ws),
184→            }));
185→            sendFrame(connectionId, {
186→              type: "q:delta",
187→              id: subId,
188→              upserted: withPaths,
189→            });
190→          } else {
191→            // Session IDs didn't match any workspaces — fall back to full snapshot
192→            const data = runQuery(sub.resource, sub.params);
193→            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
194→          }
195→        } catch (err) {
196→          // Delta lookup failed — fall back to full snapshot
197→          console.error(`[QueryEngine] Workspace delta failed, falling back to snapshot:`, err);
198→          try {
199→            const data = runQuery(sub.resource, sub.params);
200→            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
201→          } catch (snapErr) {
202→            console.error(`[QueryEngine] Snapshot fallback also failed:`, snapErr);
203→          }
204→        }
205→      } else if (sub.resource === "session" && ctx?.sessionIds?.length) {
206→        // Session with context: only push if this subscription's session is in the changed set
207→        const subscribedSessionId = readStringParam(sub.params, "sessionId");
208→        if (subscribedSessionId && ctx.sessionIds.includes(subscribedSessionId)) {
209→          try {
210→            const data = runQuery(sub.resource, sub.params);
211→            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
212→          } catch (err) {
213→            console.error(`[QueryEngine] Session snapshot push failed:`, err);
214→          }
215→        }
216→        // If session not in changed set, skip the push
217→      } else {
218→        // Other resources: push full snapshot
219→        try {
220→          const data = runQuery(sub.resource, sub.params);
221→          sendFrame(connectionId, {
222→            type: "q:snapshot",
223→            id: subId,
224→            data,
225→          });
226→        } catch (err) {
227→          console.error(`[QueryEngine] Snapshot push failed for ${sub.resource}:`, err);
228→        }
229→      }
230→    }
231→  }
232→}
233→
234→// ---- Frame Handlers ----
235→
236→function handleRequest(connectionId: string, msg: ResourceFrameInput): void {
237→  const { id, resource, params } = msg;
238→
239→  try {
240→    const typedResource = toQueryResource(resource);
241→    const data = runQuery(typedResource, params);
242→    sendFrame(connectionId, { type: "q:response", id, data });
243→  } catch (err) {
244→    sendFrame(connectionId, {
245→      type: "q:error",
246→      id,
247→      code: "QUERY_ERROR",
248→      message: err instanceof Error ? err.message : "Query failed",
249→    });
250→  }
251→}
252→
253→function handleSubscribe(connectionId: string, msg: ResourceFrameInput): void {
254→  const { id, resource, params } = msg;
255→
256→  // Validate resource upfront — fail fast before running query
257→  const typedResource = toQueryResource(resource);
258→
259→  // Send initial snapshot — only register subscription if query succeeds
260→  // (avoids zombie subscriptions when runQuery throws on invalid params)
261→  try {
262→    const data = runQuery(typedResource, params);
263→
264→    // Get or create subscription map for this connection
265→    let connSubs = subs.get(connectionId);
266→    if (!connSubs) {
267→      connSubs = new Map();
268→      subs.set(connectionId, connSubs);
269→    }
270→
271→    // Store subscription by client-assigned ID (replaces if same ID reused on reconnect)
272→    connSubs.set(id, { id, resource: typedResource, params });
273→
274→    // For messages: initialize cursor to current max seq
275→    if (typedResource === "messages") {
276→      const sessionId = readStringParam(params, "sessionId");
277→      const cursorKey = `${connectionId}:${id}`;
278→      if (sessionId) {
279→        try {
280→          const db = getDatabase();
281→          messageCursors.set(cursorKey, getMaxMessageSeq(db, sessionId));
282→        } catch {
283→          messageCursors.set(cursorKey, 0);
284→        }
285→      }
286→    }
287→
288→    sendFrame(connectionId, { type: "q:snapshot", id, data });
289→  } catch (err) {
290→    sendFrame(connectionId, {
291→      type: "q:error",
292→      id,
293→      code: "SUBSCRIBE_ERROR",
294→      message: err instanceof Error ? err.message : "Subscribe failed",
295→    });
296→  }
297→}
298→
299→function handleUnsubscribe(connectionId: string, msg: UnsubscribeFrameInput): void {
300→  const { id } = msg;
301→
302→  const connSubs = subs.get(connectionId);
303→  if (!connSubs) return;
304→
305→  const sub = connSubs.get(id);
306→  if (sub) {
307→    // Clean up message cursor
308→    if (sub.resource === "messages") {
309→      messageCursors.delete(`${connectionId}:${id}`);
310→    }
311→    connSubs.delete(id);
312→    if (connSubs.size === 0) subs.delete(connectionId);
313→  }
314→}
315→
316→function handleMutate(connectionId: string, msg: MutateFrameInput): void {
317→  const { id, action, params } = msg;
318→
319→  try {
320→    const result = runMutation(action, params);
321→    sendFrame(connectionId, {
322→      type: "q:mutate_result",
323→      id,
324→      success: true,
325→      data: result,
326→    });
327→  } catch (err) {
328→    sendFrame(connectionId, {
329→      type: "q:mutate_result",
330→      id,
331→      success: false,
332→      error: err instanceof Error ? err.message : "Mutation failed",
333→    });
334→  }
335→}
336→
337→async function handleCommand(connectionId: string, msg: CommandFrameInput): Promise<void> {
338→  const { id, command, params } = msg;
339→
340→  try {
341→    const result = await runCommand(toCommandName(command), params);
342→    sendFrame(connectionId, {
343→      type: "q:command_ack",
344→      id,
345→      accepted: true,
346→      ...result,
347→    } satisfies QServerFrame);
348→  } catch (err) {
349→    sendFrame(connectionId, {
350→      type: "q:command_ack",
351→      id,
352→      accepted: false,
353→      error: err instanceof Error ? err.message : "Command failed",
354→    } satisfies QServerFrame);
355→  }
356→}
357→
358→// ---- Tool Response Handler ----
359→
360→function handleToolResponse(msg: QueryParams): void {
361→  const requestId = typeof msg.requestId === "string" ? msg.requestId : undefined;
362→  if (!requestId) {
363→    console.error("[QueryEngine] q:tool_response missing requestId");
364→    return;
365→  }
366→
367→  if ("error" in msg && msg.error !== undefined) {
368→    const errorStr = typeof msg.error === "string" ? msg.error : JSON.stringify(msg.error);
369→    const resolved = rejectToolRelay(requestId, errorStr);
370→    if (!resolved) {
371→      console.warn(`[QueryEngine] q:tool_response for unknown requestId=${requestId} (error)`);
372→    }
373→  } else {
374→    const resolved = resolveToolRelay(requestId, msg.result);
375→    if (!resolved) {
376→      console.warn(`[QueryEngine] q:tool_response for unknown requestId=${requestId} (result)`);
377→    }
378→  }
379→}
380→
381→// ---- Query Dispatch ----
382→
383→function runQuery(resource: QueryResource, params: QueryParams): unknown {
384→  const db = getDatabase();
385→
386→  return match(resource)
387→    .with("workspaces", () => {
388→      // Return RepoGroup[] shape matching GET /workspaces/by-repo
389→      const state = readStringParam(params, "state") ?? "ready,initializing";
390→      const workspaces = getWorkspacesByRepo(db, state);
391→
392→      const grouped: Record<
393→        string,
394→        { repo_id: string; repo_name: string; sort_order: number; workspaces: unknown[] }
395→      > = {};
396→      workspaces.forEach((workspace) => {
397→        const repoId = workspace.repository_id || "unknown";
398→        if (!grouped[repoId]) {
399→          grouped[repoId] = {
400→            repo_id: repoId,
401→            repo_name: workspace.repo_name || "Unknown",
402→            sort_order: workspace.repo_sort_order ?? 999,
403→            workspaces: [],
404→          };
405→        }
406→        grouped[repoId].workspaces.push({
407→          ...workspace,
408→          workspace_path: computeWorkspacePath(workspace),
409→        });
410→      });
411→
412→      // Backfill repos that have no matching workspaces (e.g. all archived)
413→      const allRepos = getAllRepositorySummaries(db);
414→      for (const repo of allRepos) {
415→        if (!grouped[repo.id]) {
416→          grouped[repo.id] = {
417→            repo_id: repo.id,
418→            repo_name: repo.name,
419→            sort_order: repo.sort_order ?? 999,
420→            workspaces: [],
421→          };
422→        }
423→      }
424→
425→      return Object.values(grouped).sort((a, b) => a.sort_order - b.sort_order);
426→    })
427→    .with("stats", () => getStats(db))
428→    .with("sessions", () => {
429→      const workspaceId = readStringParam(params, "workspaceId");
430→      if (!workspaceId) throw new Error("sessions requires workspaceId param");
431→      return getSessionsByWorkspaceId(db, workspaceId);
432→    })
433→    .with("session", () => {
434→      const sessionId = readStringParam(params, "sessionId");
435→      if (!sessionId) throw new Error("session requires sessionId param");
436→      return getSessionById(db, sessionId);
437→    })
438→    .with("messages", () => {
439→      const sessionId = readStringParam(params, "sessionId");
440→      if (!sessionId) throw new Error("messages requires sessionId param");
441→
442→      const rows = getMessages(db, sessionId, {
443→        limit: readNumberParam(params, "limit") ?? 50,
444→        before: readNumberParam(params, "before"),
445→        after: readNumberParam(params, "after"),
446→      });
447→
448→      const hasOlder = rows.length > 0 ? hasOlderMessages(db, sessionId, rows[0].seq) : false;
449→      const hasNewer =
450→        rows.length > 0 ? hasNewerMessages(db, sessionId, rows[rows.length - 1].seq) : false;
451→
452→      return { messages: rows, has_older: hasOlder, has_newer: hasNewer };
453→    })
454→    .exhaustive();
455→}
456→
457→// ---- Mutation Dispatch ----
458→
459→function runMutation(action: string, params: QueryParams): unknown {
460→  const typedAction = toMutationName(action);
461→
462→  return match(typedAction)
463→    .with("archiveWorkspace", () => {
464→      const db = getDatabase();
465→      const workspaceId = readStringParam(params, "workspaceId");
466→      if (!workspaceId) throw new Error("archiveWorkspace requires workspaceId");
467→
468→      const workspace = getWorkspaceRaw(db, workspaceId);
469→      if (!workspace) throw new Error("Workspace not found");
470→
471→      db.prepare("UPDATE workspaces SET state = 'archived' WHERE id = ?").run(workspaceId);
472→      invalidate(["workspaces", "stats"]);
473→      return { success: true };
474→    })
475→    .with("updateWorkspaceTitle", () => {
476→      const db = getDatabase();
477→      const workspaceId = readStringParam(params, "workspaceId");
478→      const title = readStringParam(params, "title");
479→      if (!workspaceId || title === undefined) {
480→        throw new Error("updateWorkspaceTitle requires workspaceId and title");
481→      }
482→
483→      const workspace = getWorkspaceRaw(db, workspaceId);
484→      if (!workspace) throw new Error("Workspace not found");
485→
486→      db.prepare("UPDATE workspaces SET title = ? WHERE id = ?").run(title, workspaceId);
487→      invalidate(["workspaces"]);
488→      return { success: true };
489→    })
490→    .exhaustive();
491→}
492→
493→// ---- Message Delta Push ----
494→
495→function pushMessageDelta(connectionId: string, subId: string, params: QueryParams): void {
496→  const sessionId = readStringParam(params, "sessionId");
497→  if (!sessionId) return;
498→
499→  const cursorKey = `${connectionId}:${subId}`;
500→  const lastSeq = messageCursors.get(cursorKey) ?? 0;
501→
502→  try {
503→    const db = getDatabase();
504→    const newMessages = getMessagesDelta(db, sessionId, lastSeq);
505→
506→    if (newMessages.length === 0) return;
507→
508→    const maxSeq = newMessages[newMessages.length - 1].seq;
509→    messageCursors.set(cursorKey, maxSeq);
510→
511→    sendFrame(connectionId, {
512→      type: "q:delta",
513→      id: subId,
514→      upserted: newMessages,
515→      cursor: maxSeq,
516→    });
517→  } catch (err) {
518→    console.error(`[QueryEngine] Message delta push failed:`, err);
519→  }
520→}
521→
522→// ---- Helpers ----
523→
524→function sendFrame(connectionId: string, frame: QServerFrame): void {
525→  const conn = getConnection(connectionId);
526→  if (!conn) return;
527→  try {
528→    conn.ws.send(JSON.stringify(frame));
529→  } catch {
530→    // Connection may have closed
531→  }
532→}
533→
534→function parseResourceFrame(msg: QueryParams): ResourceFrameInput {
535→  return {
536→    id: requireString(msg.id, "id"),
537→    resource: requireString(msg.resource, "resource"),
538→    params: getParams(msg.params),
539→  };
540→}
541→
542→function parseUnsubscribeFrame(msg: QueryParams): UnsubscribeFrameInput {
543→  return {
544→    id: requireString(msg.id, "id"),
545→  };
546→}
547→
548→function parseMutateFrame(msg: QueryParams): MutateFrameInput {
549→  return {
550→    id: requireString(msg.id, "id"),
551→    action: requireString(msg.action, "action"),
552→    params: getParams(msg.params),
553→  };
554→}
555→
556→function getParams(value: unknown): QueryParams {
557→  if (value == null) return {};
558→  if (isRecord(value)) return value;
559→  throw new Error("Frame params must be an object");
560→}
561→
562→function requireString(value: unknown, field: string): string {
563→  if (typeof value !== "string") {
564→    throw new Error(`Frame requires string ${field}`);
565→  }
566→  return value;
567→}
568→
569→function getFrameId(msg: QueryParams): string {
570→  return typeof msg.id === "string" ? msg.id : "unknown";
571→}
572→
573→function isRecord(value: unknown): value is QueryParams {
574→  return typeof value === "object" && value !== null && !Array.isArray(value);
575→}
576→
577→function readStringParam(params: QueryParams, key: string): string | undefined {
578→  const value = params[key];
579→  return typeof value === "string" ? value : undefined;
580→}
581→
582→function readNumberParam(params: QueryParams, key: string): number | undefined {
583→  const value = params[key];
584→  return typeof value === "number" ? value : undefined;
585→}
586→
587→function isQueryResource(value: string): value is QueryResource {
588→  return (QUERY_RESOURCES as readonly string[]).includes(value);
589→}
590→
591→function toQueryResource(value: string): QueryResource {
592→  if (!isQueryResource(value)) throw new Error(`Unknown resource: ${value}`);
593→  return value;
594→}
595→
596→function isMutationName(value: string): value is MutationName {
597→  return (MUTATION_NAMES as readonly string[]).includes(value);
598→}
599→
600→function toMutationName(value: string): MutationName {
601→  if (!isMutationName(value)) throw new Error(`Unknown mutation: ${value}`);
602→  return value;
603→}
604→
605→function parseCommandFrame(msg: QueryParams): CommandFrameInput {
606→  return {
607→    id: requireString(msg.id, "id"),
608→    command: requireString(msg.command, "command"),
609→    params: getParams(msg.params),
610→  };
611→}
612→
613→function isCommandName(value: string): value is CommandName {
614→  return (COMMAND_NAMES as readonly string[]).includes(value);
615→}
616→
617→function toCommandName(value: string): CommandName {
618→  if (!isCommandName(value)) throw new Error(`Unknown command: ${value}`);
619→  return value;
620→}
621→

