app.patch("/workspaces/:id", async (c) => {
  const db = getDatabase();
  const { state, status } = parseBody(PatchWorkspaceBody, await c.req.json());

  // Manual status override (user action via PATCH)
  if (status) {
    setWorkspaceStatus(c.req.param("id"), status);
  }

  if (state) {
    db.prepare("UPDATE workspaces SET state = ? WHERE id = ?").run(state, c.req.param("id"));

    // Archive forces status → done
    if (state === "archived") {
      autoProgressStatus(c.req.param("id"), "done", { force: true });
    }

    // Unarchive: restore done → in-progress
    if (state === "ready") {
