  1→// backend/src/services/query-engine.ts
  2→// Query engine — handles q:* protocol frames for typed reactive queries.
  3→// Module singleton: subscription state + dispatch logic.
  4→// Works for both local WS and relay-tunneled connections via WsSendable.
  5→//
  6→// Subscription model: ID-keyed. Client assigns IDs ("sub_1", "sub_2") and
  7→// server echoes them back on q:snapshot/q:delta so the client can route
  8→// to the correct callback.
  9→
 10→import { match } from "ts-pattern";
 11→import { getDatabase } from "../lib/database";
 12→import {
 13→  getDashboardWorkspaces,
 14→  getStats,
 15→  getSessionsByWorkspaceId,
 16→  getSessionById,
 17→  getMessages,
 18→  hasOlderMessages,
 19→  hasNewerMessages,
 20→  getWorkspaceRaw,
 21→  getMaxMessageSeq,
 22→  getMessagesDelta,
 23→  resetStatsCache,
 24→  getWorkspacesByRepo,
 25→  getWorkspacesBySessionIds,
 26→  getAllRepositorySummaries,
 27→} from "../db";
 28→import { computeWorkspacePath } from "../middleware/workspace-loader";
 29→import { getConnection } from "./ws.service";
 30→import { resolveToolRelay, rejectToolRelay, runCommand } from "./agent";
 31→import { autoProgressStatus, setWorkspaceStatus } from "./workspace-status.service";
 32→import type { WorkspaceStatus } from "@shared/enums";
 33→import {
 34→  QUERY_RESOURCES,
 35→  MUTATION_NAMES,
 36→  COMMAND_NAMES,
 37→  type MutationName,
 38→  type CommandName,
 39→  type QueryResource,
 40→  type QServerFrame,
 41→} from "@shared/types/query-protocol";
 42→
 43→// ---- Subscription State ----
 44→
 45→type QueryParams = Record<string, unknown>;
 46→
 47→interface ResourceFrameInput {
 48→  id: string;
 49→  resource: string;
 50→  params: QueryParams;
 51→}
 52→
 53→interface UnsubscribeFrameInput {
 54→  id: string;
 55→}
 56→
 57→interface MutateFrameInput {
 58→  id: string;
 59→  action: string;
 60→  params: QueryParams;
 61→}
 62→
 63→interface CommandFrameInput {
 64→  id: string;
 65→  command: string;
 66→  params: QueryParams;
 67→}
 68→
 69→interface Sub {
 70→  id: string;
 71→  resource: QueryResource;
 72→  params: QueryParams;
 73→}
 74→
 75→/** Per-connection active subscriptions, keyed by client-assigned sub ID. */
 76→const subs = new Map<string, Map<string, Sub>>();
 77→
 78→/** For messages: track last seen seq per subscription for delta push.
 79→ *  Key: `${connectionId}:${subId}` → lastSeq */
 80→const messageCursors = new Map<string, number>();
 81→
 82→// ---- Public API ----
 83→
 84→/**
 85→ * Handle an incoming q:* frame from an authenticated connection.
 86→ * Registered as onQueryFrame in ws.service protocol handlers.
 87→ */
 88→export function handleFrame(connectionId: string, msg: QueryParams): void {
 89→  const type = typeof msg.type === "string" ? msg.type : "unknown";
 90→
 91→  try {
 92→    match(type)
 93→      .with("q:request", () => {
 94→        handleRequest(connectionId, parseResourceFrame(msg));
 95→      })
 96→      .with("q:subscribe", () => {
 97→        handleSubscribe(connectionId, parseResourceFrame(msg));
 98→      })
 99→      .with("q:unsubscribe", () => {
100→        handleUnsubscribe(connectionId, parseUnsubscribeFrame(msg));
101→      })
102→      .with("q:mutate", () => {
103→        handleMutate(connectionId, parseMutateFrame(msg));
104→      })
105→      .with("q:command", () => {
106→        handleCommand(connectionId, parseCommandFrame(msg));
107→      })
108→      .with("q:tool_response", () => {
109→        handleToolResponse(msg);
110→      })
111→      .otherwise(() => {
112→        sendFrame(connectionId, {
113→          type: "q:error",
114→          id: getFrameId(msg),
115→          code: "UNKNOWN_FRAME",
116→          message: `Unknown query frame type: ${type}`,
117→        });
118→      });
119→  } catch (err) {
120→    sendFrame(connectionId, {
121→      type: "q:error",
122→      id: getFrameId(msg),
123→      code: "INVALID_FRAME",
124→      message: err instanceof Error ? err.message : "Invalid query frame",
125→    });
126→  }
127→}
128→
129→/** Remove all subscriptions for a connection (cleanup on disconnect). */
130→export function removeSubs(connectionId: string): void {
131→  const connSubs = subs.get(connectionId);
132→  if (connSubs) {
133→    for (const [subId, sub] of connSubs) {
134→      if (sub.resource === "messages") {
135→        messageCursors.delete(`${connectionId}:${subId}`);
136→      }
137→    }
138→    subs.delete(connectionId);
139→  }
140→}
141→
142→/** Optional context for targeted invalidation (e.g., which sessions changed). */
143→interface InvalidateContext {
144→  sessionIds?: string[];
145→}
146→
147→/**
148→ * Push-first invalidation: re-run queries for active subscribers and push
149→ * fresh snapshots or deltas.
150→ *
151→ * Messages use q:delta (cursor-based) instead of full snapshots.
152→ * When `ctx.sessionIds` is provided, workspace subscribers receive a targeted
153→ * q:delta (only the changed workspaces) instead of a full q:snapshot.
154→ */
155→export function invalidate(resources: QueryResource[], ctx?: InvalidateContext): void {
156→  if (resources.includes("stats")) {
157→    resetStatsCache();
158→  }
159→
160→  // Phase 1: Push fresh data to active subscribers
161→  for (const [connectionId, connSubs] of subs) {
162→    if (!getConnection(connectionId)) {
163→      removeSubs(connectionId);
164→      continue;
165→    }
166→
167→    for (const [subId, sub] of connSubs) {
168→      if (!resources.includes(sub.resource)) continue;
169→
170→      if (sub.resource === "messages") {
171→        // Messages: push delta (new messages since last cursor)
172→        pushMessageDelta(connectionId, subId, sub.params);
173→      } else if (sub.resource === "workspaces" && ctx?.sessionIds?.length) {
174→        // Workspaces with session context: try targeted delta
175→        try {
176→          const db = getDatabase();
177→          const stateFilter = readStringParam(sub.params, "state") ?? "ready,initializing";
178→          const allowedStates = new Set(stateFilter.split(",").map((s) => s.trim()));
179→          const changedWorkspaces = getWorkspacesBySessionIds(db, ctx.sessionIds).filter((ws) =>
180→            allowedStates.has(ws.state)
181→          );
182→          if (changedWorkspaces.length > 0) {
183→            const withPaths = changedWorkspaces.map((ws) => ({
184→              ...ws,
185→              workspace_path: computeWorkspacePath(ws),
186→            }));
187→            sendFrame(connectionId, {
188→              type: "q:delta",
189→              id: subId,
190→              upserted: withPaths,
191→            });
192→          } else {
193→            // Session IDs didn't match any workspaces — fall back to full snapshot
194→            const data = runQuery(sub.resource, sub.params);
195→            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
196→          }
197→        } catch (err) {
198→          // Delta lookup failed — fall back to full snapshot
199→          console.error(`[QueryEngine] Workspace delta failed, falling back to snapshot:`, err);
200→          try {
201→            const data = runQuery(sub.resource, sub.params);
202→            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
203→          } catch (snapErr) {
204→            console.error(`[QueryEngine] Snapshot fallback also failed:`, snapErr);
205→          }
206→        }
207→      } else if (sub.resource === "session" && ctx?.sessionIds?.length) {
208→        // Session with context: only push if this subscription's session is in the changed set
209→        const subscribedSessionId = readStringParam(sub.params, "sessionId");
210→        if (subscribedSessionId && ctx.sessionIds.includes(subscribedSessionId)) {
211→          try {
212→            const data = runQuery(sub.resource, sub.params);
213→            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
214→          } catch (err) {
215→            console.error(`[QueryEngine] Session snapshot push failed:`, err);
216→          }
217→        }
218→        // If session not in changed set, skip the push
219→      } else {
220→        // Other resources: push full snapshot
221→        try {
222→          const data = runQuery(sub.resource, sub.params);
223→          sendFrame(connectionId, {
224→            type: "q:snapshot",
225→            id: subId,
226→            data,
227→          });
228→        } catch (err) {
229→          console.error(`[QueryEngine] Snapshot push failed for ${sub.resource}:`, err);
230→        }
231→      }
232→    }
233→  }
234→}
235→
236→// ---- Frame Handlers ----
237→
238→function handleRequest(connectionId: string, msg: ResourceFrameInput): void {
239→  const { id, resource, params } = msg;
240→
241→  try {
242→    const typedResource = toQueryResource(resource);
243→    const data = runQuery(typedResource, params);
244→    sendFrame(connectionId, { type: "q:response", id, data });
245→  } catch (err) {
246→    sendFrame(connectionId, {
247→      type: "q:error",
248→      id,
249→      code: "QUERY_ERROR",
250→      message: err instanceof Error ? err.message : "Query failed",
251→    });
252→  }
253→}
254→
255→function handleSubscribe(connectionId: string, msg: ResourceFrameInput): void {
256→  const { id, resource, params } = msg;
257→
258→  // Validate resource upfront — fail fast before running query
259→  const typedResource = toQueryResource(resource);
260→
261→  // Send initial snapshot — only register subscription if query succeeds
262→  // (avoids zombie subscriptions when runQuery throws on invalid params)
263→  try {
264→    const data = runQuery(typedResource, params);
265→
266→    // Get or create subscription map for this connection
267→    let connSubs = subs.get(connectionId);
268→    if (!connSubs) {
269→      connSubs = new Map();
270→      subs.set(connectionId, connSubs);
271→    }
272→
273→    // Store subscription by client-assigned ID (replaces if same ID reused on reconnect)
274→    connSubs.set(id, { id, resource: typedResource, params });
275→
276→    // For messages: initialize cursor to current max seq
277→    if (typedResource === "messages") {
278→      const sessionId = readStringParam(params, "sessionId");
279→      const cursorKey = `${connectionId}:${id}`;
280→      if (sessionId) {
281→        try {
282→          const db = getDatabase();
283→          messageCursors.set(cursorKey, getMaxMessageSeq(db, sessionId));
284→        } catch {
285→          messageCursors.set(cursorKey, 0);
286→        }
287→      }
288→    }
289→
290→    sendFrame(connectionId, { type: "q:snapshot", id, data });
291→  } catch (err) {
292→    sendFrame(connectionId, {
293→      type: "q:error",
294→      id,
295→      code: "SUBSCRIBE_ERROR",
296→      message: err instanceof Error ? err.message : "Subscribe failed",
297→    });
298→  }
299→}
300→
301→function handleUnsubscribe(connectionId: string, msg: UnsubscribeFrameInput): void {
302→  const { id } = msg;
303→
304→  const connSubs = subs.get(connectionId);
305→  if (!connSubs) return;
306→
307→  const sub = connSubs.get(id);
308→  if (sub) {
309→    // Clean up message cursor
310→    if (sub.resource === "messages") {
311→      messageCursors.delete(`${connectionId}:${id}`);
312→    }
313→    connSubs.delete(id);
314→    if (connSubs.size === 0) subs.delete(connectionId);
315→  }
316→}
317→
318→function handleMutate(connectionId: string, msg: MutateFrameInput): void {
319→  const { id, action, params } = msg;
320→
321→  try {
322→    const result = runMutation(action, params);
323→    sendFrame(connectionId, {
324→      type: "q:mutate_result",
325→      id,
326→      success: true,
327→      data: result,
328→    });
329→  } catch (err) {
330→    sendFrame(connectionId, {
331→      type: "q:mutate_result",
332→      id,
333→      success: false,
334→      error: err instanceof Error ? err.message : "Mutation failed",
335→    });
336→  }
337→}
338→
339→async function handleCommand(connectionId: string, msg: CommandFrameInput): Promise<void> {
340→  const { id, command, params } = msg;
341→
342→  try {
343→    const result = await runCommand(toCommandName(command), params);
344→    sendFrame(connectionId, {
345→      type: "q:command_ack",
346→      id,
347→      accepted: true,
348→      ...result,
349→    } satisfies QServerFrame);
350→  } catch (err) {
351→    sendFrame(connectionId, {
352→      type: "q:command_ack",
353→      id,
354→      accepted: false,
355→      error: err instanceof Error ? err.message : "Command failed",
356→    } satisfies QServerFrame);
357→  }
358→}
359→
360→// ---- Tool Response Handler ----
361→
362→function handleToolResponse(msg: QueryParams): void {
363→  const requestId = typeof msg.requestId === "string" ? msg.requestId : undefined;
364→  if (!requestId) {
365→    console.error("[QueryEngine] q:tool_response missing requestId");
366→    return;
367→  }
368→
369→  if ("error" in msg && msg.error !== undefined) {
370→    const errorStr = typeof msg.error === "string" ? msg.error : JSON.stringify(msg.error);
371→    const resolved = rejectToolRelay(requestId, errorStr);
372→    if (!resolved) {
373→      console.warn(`[QueryEngine] q:tool_response for unknown requestId=${requestId} (error)`);
374→    }
375→  } else {
376→    const resolved = resolveToolRelay(requestId, msg.result);
377→    if (!resolved) {
378→      console.warn(`[QueryEngine] q:tool_response for unknown requestId=${requestId} (result)`);
379→    }
380→  }
381→}
382→
383→// ---- Query Dispatch ----
384→
385→function runQuery(resource: QueryResource, params: QueryParams): unknown {
386→  const db = getDatabase();
387→
388→  return match(resource)
389→    .with("workspaces", () => {
390→      // Return RepoGroup[] shape matching GET /workspaces/by-repo
391→      const state = readStringParam(params, "state") ?? "ready,initializing";
392→      const workspaces = getWorkspacesByRepo(db, state);
393→
394→      const grouped: Record<
395→        string,
396→        { repo_id: string; repo_name: string; sort_order: number; workspaces: unknown[] }
397→      > = {};
398→      workspaces.forEach((workspace) => {
399→        const repoId = workspace.repository_id || "unknown";
400→        if (!grouped[repoId]) {
401→          grouped[repoId] = {
402→            repo_id: repoId,
403→            repo_name: workspace.repo_name || "Unknown",
404→            sort_order: workspace.repo_sort_order ?? 999,
405→            workspaces: [],
406→          };
407→        }
408→        grouped[repoId].workspaces.push({
409→          ...workspace,
410→          workspace_path: computeWorkspacePath(workspace),
411→        });
412→      });
413→
414→      // Backfill repos that have no matching workspaces (e.g. all archived)
415→      const allRepos = getAllRepositorySummaries(db);
416→      for (const repo of allRepos) {
417→        if (!grouped[repo.id]) {
418→          grouped[repo.id] = {
419→            repo_id: repo.id,
420→            repo_name: repo.name,
421→            sort_order: repo.sort_order ?? 999,
422→            workspaces: [],
423→          };
424→        }
425→      }
426→
427→      return Object.values(grouped).sort((a, b) => a.sort_order - b.sort_order);
428→    })
429→    .with("stats", () => getStats(db))
430→    .with("sessions", () => {
431→      const workspaceId = readStringParam(params, "workspaceId");
432→      if (!workspaceId) throw new Error("sessions requires workspaceId param");
433→      return getSessionsByWorkspaceId(db, workspaceId);
434→    })
435→    .with("session", () => {
436→      const sessionId = readStringParam(params, "sessionId");
437→      if (!sessionId) throw new Error("session requires sessionId param");
438→      return getSessionById(db, sessionId);
439→    })
440→    .with("messages", () => {
441→      const sessionId = readStringParam(params, "sessionId");
442→      if (!sessionId) throw new Error("messages requires sessionId param");
443→
444→      const rows = getMessages(db, sessionId, {
445→        limit: readNumberParam(params, "limit") ?? 50,
446→        before: readNumberParam(params, "before"),
447→        after: readNumberParam(params, "after"),
448→      });
449→
450→      const hasOlder = rows.length > 0 ? hasOlderMessages(db, sessionId, rows[0].seq) : false;
451→      const hasNewer =
452→        rows.length > 0 ? hasNewerMessages(db, sessionId, rows[rows.length - 1].seq) : false;
453→
454→      return { messages: rows, has_older: hasOlder, has_newer: hasNewer };
455→    })
456→    .exhaustive();
457→}
458→
459→// ---- Mutation Dispatch ----
460→
461→function runMutation(action: string, params: QueryParams): unknown {
462→  const typedAction = toMutationName(action);
463→
464→  return match(typedAction)
465→    .with("archiveWorkspace", () => {
466→      const db = getDatabase();
467→      const workspaceId = readStringParam(params, "workspaceId");
468→      if (!workspaceId) throw new Error("archiveWorkspace requires workspaceId");
469→
470→      const workspace = getWorkspaceRaw(db, workspaceId);
471→      if (!workspace) throw new Error("Workspace not found");
472→
473→      db.prepare("UPDATE workspaces SET state = 'archived' WHERE id = ?").run(workspaceId);
474→      autoProgressStatus(workspaceId, "done", { force: true });
475→      invalidate(["workspaces", "stats"]);
476→      return { success: true };
477→    })
478→    .with("updateWorkspaceTitle", () => {
479→      const db = getDatabase();
480→      const workspaceId = readStringParam(params, "workspaceId");
481→      const title = readStringParam(params, "title");
482→      if (!workspaceId || title === undefined) {
483→        throw new Error("updateWorkspaceTitle requires workspaceId and title");
484→      }
485→
486→      const workspace = getWorkspaceRaw(db, workspaceId);
487→      if (!workspace) throw new Error("Workspace not found");
488→
489→      db.prepare("UPDATE workspaces SET title = ? WHERE id = ?").run(title, workspaceId);
490→      invalidate(["workspaces"]);
491→      return { success: true };
492→    })
493→    .with("updateWorkspaceStatus", () => {
494→      const workspaceId = readStringParam(params, "workspaceId");
495→      const status = readStringParam(params, "status");
496→      if (!workspaceId || !status) {
497→        throw new Error("updateWorkspaceStatus requires workspaceId and status");
498→      }
499→      setWorkspaceStatus(workspaceId, status as WorkspaceStatus);
500→      invalidate(["workspaces", "stats"]);
501→      return { success: true };
502→    })
503→    .exhaustive();
504→}
505→
506→// ---- Message Delta Push ----
507→
508→function pushMessageDelta(connectionId: string, subId: string, params: QueryParams): void {
509→  const sessionId = readStringParam(params, "sessionId");
510→  if (!sessionId) return;
511→
512→  const cursorKey = `${connectionId}:${subId}`;
513→  const lastSeq = messageCursors.get(cursorKey) ?? 0;
514→
515→  try {
516→    const db = getDatabase();
517→    const newMessages = getMessagesDelta(db, sessionId, lastSeq);
518→
519→    if (newMessages.length === 0) return;
520→
521→    const maxSeq = newMessages[newMessages.length - 1].seq;
522→    messageCursors.set(cursorKey, maxSeq);
523→
524→    sendFrame(connectionId, {
525→      type: "q:delta",
526→      id: subId,
527→      upserted: newMessages,
528→      cursor: maxSeq,
529→    });
530→  } catch (err) {
531→    console.error(`[QueryEngine] Message delta push failed:`, err);
532→  }
533→}
534→
535→// ---- Helpers ----
536→
537→function sendFrame(connectionId: string, frame: QServerFrame): void {
538→  const conn = getConnection(connectionId);
539→  if (!conn) return;
540→  try {
541→    conn.ws.send(JSON.stringify(frame));
542→  } catch {
543→    // Connection may have closed
544→  }
545→}
546→
547→function parseResourceFrame(msg: QueryParams): ResourceFrameInput {
548→  return {
549→    id: requireString(msg.id, "id"),
550→    resource: requireString(msg.resource, "resource"),
551→    params: getParams(msg.params),
552→  };
553→}
554→
555→function parseUnsubscribeFrame(msg: QueryParams): UnsubscribeFrameInput {
556→  return {
557→    id: requireString(msg.id, "id"),
558→  };
559→}
560→
561→function parseMutateFrame(msg: QueryParams): MutateFrameInput {
562→  return {
563→    id: requireString(msg.id, "id"),
564→    action: requireString(msg.action, "action"),
565→    params: getParams(msg.params),
566→  };
567→}
568→
569→function getParams(value: unknown): QueryParams {
570→  if (value == null) return {};
571→  if (isRecord(value)) return value;
572→  throw new Error("Frame params must be an object");
573→}
574→
575→function requireString(value: unknown, field: string): string {
576→  if (typeof value !== "string") {
577→    throw new Error(`Frame requires string ${field}`);
578→  }
579→  return value;
580→}
581→
582→function getFrameId(msg: QueryParams): string {
583→  return typeof msg.id === "string" ? msg.id : "unknown";
584→}
585→
586→function isRecord(value: unknown): value is QueryParams {
587→  return typeof value === "object" && value !== null && !Array.isArray(value);
588→}
589→
590→function readStringParam(params: QueryParams, key: string): string | undefined {
591→  const value = params[key];
592→  return typeof value === "string" ? value : undefined;
593→}
594→
595→function readNumberParam(params: QueryParams, key: string): number | undefined {
596→  const value = params[key];
597→  return typeof value === "number" ? value : undefined;
598→}
599→
600→function isQueryResource(value: string): value is QueryResource {
601→  return (QUERY_RESOURCES as readonly string[]).includes(value);
602→}
603→
604→function toQueryResource(value: string): QueryResource {
605→  if (!isQueryResource(value)) throw new Error(`Unknown resource: ${value}`);
606→  return value;
607→}
608→
609→function isMutationName(value: string): value is MutationName {
610→  return (MUTATION_NAMES as readonly string[]).includes(value);
611→}
612→
613→function toMutationName(value: string): MutationName {
614→  if (!isMutationName(value)) throw new Error(`Unknown mutation: ${value}`);
615→  return value;
616→}
617→
618→function parseCommandFrame(msg: QueryParams): CommandFrameInput {
619→  return {
620→    id: requireString(msg.id, "id"),
621→    command: requireString(msg.command, "command"),
622→    params: getParams(msg.params),
623→  };
624→}
625→
626→function isCommandName(value: string): value is CommandName {
627→  return (COMMAND_NAMES as readonly string[]).includes(value);
628→}
629→
630→function toCommandName(value: string): CommandName {
631→  if (!isCommandName(value)) throw new Error(`Unknown command: ${value}`);
632→  return value;
633→}
