111→      try {
112→        const ws = getWorkspaceById(db, id);
113→        if (ws && ws.root_path) {
114→          const wsPath = computeWorkspacePath(ws);
115→          const manifest = readManifestWithFallback(wsPath, ws.root_path);
116→          const archiveCmd = manifest ? getArchiveCommand(manifest) : null;
117→          if (archiveCmd) {
118→            const archiveEnv = getOpenDevsEnv(manifest!, {
119→              id: ws.id,
120→              rootPath: ws.root_path,
121→              workspacePath: wsPath,
122→            });
123→            const archiveProc = spawn("sh", ["-c", archiveCmd], {
124→              cwd: wsPath,
125→              env: { ...process.env, ...archiveEnv },
126→              stdio: "ignore",
127→              detached: false,
128→            });
129→            archiveProc.on("error", (err) => {
130→              console.error(`Archive hook error for workspace ${id}:`, err.message);
131→            });
132→            archiveProc.unref();
133→          }
134→        }
135→      } catch (err) {
136→        console.warn("[WORKSPACE] Archive lifecycle hook failed (continuing):", err);
137→      }
138→    }
139→
140→    // Unarchive: restore done → in-progress
141→    if (state === "ready") {
142→      const ws = getWorkspaceRaw(db, id);
143→      if (ws?.status === "done") {
144→        autoProgressStatus(id, "in-progress", { force: true });
145→      }
146→    }
147→  }
