153→// Create workspace
154→app.post("/workspaces", async (c) => {
155→  const db = getDatabase();
156→  const { repository_id } = parseBody(CreateWorkspaceBody, await c.req.json());
157→
158→  const repo = getRepositoryById(db, repository_id);
159→  if (!repo) throw new NotFoundError("Repository not found");
160→
161→  const workspace_name = generateUniqueName(db);
162→  const parent_branch = repo.git_default_branch || "main";
163→  const workspaceId = uuidv7();
164→
165→  let branchPrefix = "workspace";
166→  try {
167→    const gitUser = execSync("git config user.name", { cwd: repo.root_path!, encoding: "utf8" })
168→      .trim()
169→      .toLowerCase()
170→      .replace(/[^a-z0-9_-]/g, "-");
171→    if (gitUser) branchPrefix = gitUser;
172→  } catch {}
173→  const placeholderBranchName = `${branchPrefix}/${workspace_name}`;
174→
175→  // ─── IMPORTANT: Remote-first branch strategy ───────────────────────
176→  // We ALWAYS want worktrees branched from origin/<parent_branch>, not
177→  // local <parent_branch>. Diffs are computed against origin/<branch>
178→  // (see resolve_parent_branch in git.rs and git.service.ts). If origin
179→  // is stale, the merge-base drifts and every file since the divergence
180→  // shows as "changed" — producing hundreds of phantom file changes.
181→  //
182→  // Fetch the remote branch before creating the worktree so that:
183→  // 1. The worktree starts from the latest upstream commit
184→  // 2. Diff merge-base matches what we branched from (zero phantom changes)
185→  // 3. PRs will be clean against the upstream target
186→  //
187→  // This is a non-blocking fetch (~1-3s on a warm connection). Workspace
188→  // creation is already async (worktree add runs in a child process) and
189→  // correctness matters more here.
190→  // ───────────────────────────────────────────────────────────────────
191→  try {
192→    await execFileAsync("git", ["fetch", "origin", parent_branch], {
193→      cwd: repo.root_path!,
194→      timeout: 15000,
195→    });
196→  } catch (fetchErr) {
197→    // Non-fatal: if fetch fails (offline, no remote, etc.), fall back to
198→    // whatever local state we have. The worktree will still be created
199→    // from the local branch — diffs might be off but it's better than
200→    // blocking workspace creation entirely.
201→    console.warn(
202→      `[WORKSPACE] git fetch origin ${parent_branch} failed (continuing with local):`,
203→      fetchErr
204→    );
205→  }
206→
207→  db.prepare(
208→    `
209→    INSERT INTO workspaces (
210→      id, repository_id, slug, git_branch,
211→      git_target_branch, state, updated_at
212→    ) VALUES (?, ?, ?, ?, ?, ?, datetime('now'))
213→  `
214→  ).run(
215→    workspaceId,
216→    repository_id,
217→    workspace_name,
218→    placeholderBranchName,
219→    parent_branch,
220→    "initializing"
221→  );
222→
223→  // Branch from origin/<parent_branch> when available (fetched above).
224→  // Falls back to local <parent_branch> if remote doesn't exist.
225→  const worktreeBase = await (async () => {
226→    try {
227→      await execFileAsync(
228→        "git",
229→        ["show-ref", "--verify", "--quiet", `refs/remotes/origin/${parent_branch}`],
230→        {
231→          cwd: repo.root_path!,
232→          timeout: 2000,
233→        }
234→      );
235→      return `origin/${parent_branch}`;
236→    } catch {
237→      return parent_branch;
238→    }
239→  })();
240→
241→  const workspacePath = path.join(repo.root_path!, ".opendevs", workspace_name);
242→
243→  // Fire-and-forget: run the init pipeline async (don't await).
244→  // Pipeline handles: worktree creation → deps install → .env copy → session creation.
245→  // Progress events flow: stdout → Electron main process → IPC events → Frontend.
246→  // On fatal failure: reverse cleanup (rm dir, prune worktree, delete branch).
247→  initializeWorkspace({
248→    workspaceId,
249→    repositoryId: repository_id,
250→    repoRootPath: repo.root_path!,
251→    workspacePath,
252→    branchName: placeholderBranchName,
253→    worktreeBase,
254→    parentBranch: parent_branch,
255→  })
256→    .then(() => {
257→      // Workspace is ready — check for manifest setup script
258→      const manifest = readManifestWithFallback(workspacePath, repo.root_path!);
259→      const setupCmd = manifest ? getSetupCommand(manifest) : null;
260→      if (setupCmd && manifest) {
261→        db.prepare("UPDATE workspaces SET setup_status = 'running' WHERE id = ?").run(workspaceId);
262→        const setupEnv = getOpenDevsEnv(manifest, {
263→          id: workspaceId,
264→          rootPath: repo.root_path!,
265→          workspacePath,
266→        });
267→        runSetupScript(db, workspaceId, setupCmd, setupEnv, workspacePath);
268→      }
269→    })
270→    .catch((err) => {
271→      // Belt-and-suspenders: initializeWorkspace handles its own errors,
272→      // but if something truly unexpected escapes, don't leave workspace stuck.
273→      console.error("[WORKSPACE] Unhandled init pipeline error:", err);
274→      try {
275→        db.prepare(
276→          "UPDATE workspaces SET state = 'error', init_stage = 'unhandled', error_message = 'Unhandled init pipeline error' WHERE id = ? AND state = 'initializing'"
277→        ).run(workspaceId);
278→        invalidate(["workspaces", "stats"]);
279→      } catch {}
280→    });
281→
282→  const workspace = getWorkspaceForMiddleware(db, workspaceId);
283→  if (!workspace) throw new NotFoundError("Workspace not found after creation");
284→
285→  // Push immediately so clients see the workspace in 'initializing' state.
286→  // Query-protocol subscribers get snapshots + q:invalidate for unmounted caches.
287→  // The init pipeline will invalidate again when it transitions to 'ready'.
288→  invalidate(["workspaces", "stats"]);
289→
290→  return c.json({ ...workspace, workspace_path: computeWorkspacePath(workspace) });
291→});
