330→// ─── Manifest & Task Endpoints ──────────────────────────────
331→
332→// Get parsed manifest + normalized tasks for a workspace
333→app.get("/workspaces/:id/manifest", withWorkspace, (c) => {
334→  const workspace = c.get("workspace");
335→  const workspacePath = c.get("workspacePath");
336→  if (!workspace.root_path) {
337→    return c.json({ manifest: null, tasks: [] });
338→  }
339→  const manifest = readManifestWithFallback(workspacePath, workspace.root_path);
340→  if (!manifest) return c.json({ manifest: null, tasks: [] });
341→  const tasks = getNormalizedTasks(manifest);
342→  return c.json({ manifest, tasks });
343→});
344→
345→// Retry failed setup
346→app.post("/workspaces/:id/retry-setup", withWorkspace, (c) => {
347→  const db = getDatabase();
348→  const workspace = c.get("workspace");
349→  const workspacePath = c.get("workspacePath");
350→
351→  if (workspace.setup_status !== "failed") {
352→    throw new ValidationError("Can only retry when setup_status is failed");
353→  }
354→
355→  if (!workspace.root_path) {
356→    throw new ValidationError("Repository path not found");
357→  }
358→
359→  // Re-read manifest (AI agent may have fixed it, or it was added to repo root via settings)
360→  const manifest = readManifestWithFallback(workspacePath, workspace.root_path);
361→  const setupCmd = manifest ? getSetupCommand(manifest) : null;
362→  if (!setupCmd || !manifest) {
363→    db.prepare(
364→      "UPDATE workspaces SET setup_status = 'none', error_message = NULL, updated_at = datetime('now') WHERE id = ?"
365→    ).run(workspace.id);
366→    return c.json({ setup_status: "none" });
367→  }
368→
369→  db.prepare(
370→    "UPDATE workspaces SET setup_status = 'running', error_message = NULL, updated_at = datetime('now') WHERE id = ?"
371→  ).run(workspace.id);
372→
373→  const setupEnv = getOpenDevsEnv(manifest, {
374→    id: workspace.id,
375→    rootPath: workspace.root_path,
376→    workspacePath,
377→  });
378→  runSetupScript(db, workspace.id, setupCmd, setupEnv, workspacePath);
379→
380→  return c.json({ setup_status: "running" });
381→});
382→
383→// Get setup logs
384→app.get("/workspaces/:id/setup-logs", withWorkspace, (c) => {
385→  const workspace = c.get("workspace");
386→  const setupLogPath = path.join(os.tmpdir(), `opendevs-${workspace.id}-setup.log`);
387→  try {
388→    if (!fs.existsSync(setupLogPath)) return c.json({ logs: null });
389→    const logs = fs.readFileSync(setupLogPath, "utf8");
390→    return c.json({ logs });
391→  } catch {
392→    return c.json({ logs: null });
393→  }
394→});
395→
396→// Run a task — validates task exists, returns info for frontend PTY spawn
397→app.post("/workspaces/:id/tasks/:name/run", withWorkspace, (c) => {
398→  const workspace = c.get("workspace");
399→  const workspacePath = c.get("workspacePath");
400→  const taskName = c.req.param("name");
401→
402→  if (!workspace.root_path) {
403→    throw new ValidationError("Repository path not found");
404→  }
405→
406→  const manifest = readManifestWithFallback(workspacePath, workspace.root_path);
407→  if (!manifest) throw new NotFoundError("No opendevs.json manifest found");
408→
409→  const tasks = getNormalizedTasks(manifest);
410→  const task = tasks.find((t) => t.name === taskName);
411→  if (!task) throw new NotFoundError(`Task "${taskName}" not found in manifest`);
412→
413→  const ptyId = `task-${workspace.id}-${taskName}-${Date.now()}`;
414→  const env = {
415→    ...(manifest.env ?? {}),
416→    ...task.env,
417→    OPENDEVS_ROOT_PATH: workspace.root_path,
418→    OPENDEVS_WORKSPACE_PATH: workspacePath,
419→    OPENDEVS_WORKSPACE_ID: workspace.id,
420→  };
421→
422→  return c.json({
423→    ptyId,
424→    command: task.command,
425→    cwd: workspacePath,
426→    env,
427→    persistent: task.persistent,
428→    mode: task.mode,
429→  });
430→});
431→
