 1→import { STICKY_STATUSES, STATUS_RANK, type WorkspaceStatus } from "@shared/enums";
 2→import { getDatabase } from "../lib/database";
 3→import { getWorkspaceRaw } from "../db";
 4→
 5→/**
 6→ * Auto-progress a workspace's workflow status.
 7→ *
 8→ * Rules:
 9→ * - Sticky states (backlog, canceled) resist auto-progression unless forced
10→ * - Won't regress (in-review won't go back to in-progress)
11→ * - Force mode (used by archive) overrides both guards
12→ *
13→ * IMPORTANT: Does NOT call invalidate(). The caller is responsible for
14→ * invalidation after its own DB writes. This prevents double WS pushes.
15→ */
16→export function autoProgressStatus(
17→  workspaceId: string,
18→  target: WorkspaceStatus,
19→  opts: { force?: boolean } = {},
20→): void {
21→  const db = getDatabase();
22→  const ws = getWorkspaceRaw(db, workspaceId);
23→  if (!ws) return;
24→
25→  const current = ws.status as WorkspaceStatus;
26→
27→  if (!opts.force) {
28→    // Sticky states resist auto-progression (backlog, canceled)
29→    if (STICKY_STATUSES.has(current)) return;
30→    // Don't regress (in-review → in-progress is wrong)
31→    if (STATUS_RANK[target] <= STATUS_RANK[current]) return;
32→  }
33→
34→  db.prepare("UPDATE workspaces SET status = ? WHERE id = ?").run(target, workspaceId);
35→}
36→
37→/**
38→ * Explicitly set workspace status (user override). No sticky/flow guards.
39→ * Used by the updateWorkspaceStatus mutation.
40→ */
41→export function setWorkspaceStatus(workspaceId: string, status: WorkspaceStatus): void {
42→  const db = getDatabase();
43→  db.prepare("UPDATE workspaces SET status = ? WHERE id = ?").run(status, workspaceId);
44→}
