 1→import Database from "better-sqlite3";
 2→import path from "path";
 3→import fs from "fs";
 4→import os from "os";
 5→import { SCHEMA_SQL, MIGRATIONS } from "@shared/schema";
 6→import { backfillWorkspaceStatus } from "../db";
 7→
 8→const DEFAULT_DB_PATH = path.join(
 9→  process.env.HOME || os.homedir(),
10→  "Library/Application Support/com.opendevs.app/opendevs.db"
11→);
12→
13→const DB_PATH = process.env.DATABASE_PATH || DEFAULT_DB_PATH;
14→
15→let dbInstance: Database.Database | null = null;
16→
17→function initDatabase(): Database.Database {
18→  if (dbInstance) {
19→    return dbInstance;
20→  }
21→
22→  // Ensure parent directory exists (first launch)
23→  const dbDir = path.dirname(DB_PATH);
24→  if (!fs.existsSync(dbDir)) {
25→    fs.mkdirSync(dbDir, { recursive: true });
26→  }
27→
28→  console.log("Opening database:", DB_PATH);
29→
30→  try {
31→    dbInstance = new Database(DB_PATH);
32→    dbInstance.pragma("journal_mode = WAL");
33→    dbInstance.pragma("foreign_keys = ON");
34→    dbInstance.pragma("busy_timeout = 5000");
35→    dbInstance.pragma("optimize");
36→
37→    // Create all tables, indexes, and triggers (idempotent)
38→    dbInstance.exec(SCHEMA_SQL);
39→
40→    // Post-launch migrations: add new columns to existing tables.
41→    // Each ALTER TABLE may fail with "duplicate column" if already applied — skip those.
42→    for (const sql of MIGRATIONS) {
43→      try {
44→        dbInstance.exec(sql);
45→      } catch (e: unknown) {
46→        const msg = e instanceof Error ? e.message : "";
47→        if (!msg.includes("duplicate column") && !msg.includes("no such table")) throw e;
48→      }
49→    }
50→
51→    // Backfill workspace status for existing databases (idempotent — safe to run repeatedly)
52→    try {
53→      backfillWorkspaceStatus(dbInstance);
54→    } catch {
55→      // Backfill is best-effort — may fail if status column doesn't exist yet (shouldn't happen)
56→    }
57→
58→    console.log("Database connected");
59→    return dbInstance;
60→  } catch (error) {
61→    console.error("Failed to open database:", error);
62→    throw error;
63→  }
64→}
65→
66→function getDatabase(): Database.Database {
67→  if (!dbInstance) {
68→    throw new Error("Database not initialized. Call initDatabase() first.");
69→  }
70→  return dbInstance;
71→}
72→
73→function closeDatabase(): void {
74→  if (dbInstance) {
75→    console.log("Closing database connection");
76→    dbInstance.pragma("optimize");
77→    dbInstance.close();
78→    dbInstance = null;
79→  }
80→}
81→
82→export { initDatabase, getDatabase, closeDatabase, DB_PATH };
