507→// ---- Message Delta Push ----
508→
509→function pushMessageDelta(connectionId: string, subId: string, params: QueryParams): void {
510→  const sessionId = readStringParam(params, "sessionId");
511→  if (!sessionId) return;
512→
513→  const cursorKey = `${connectionId}:${subId}`;
514→  const lastSeq = messageCursors.get(cursorKey) ?? 0;
515→
516→  try {
517→    const db = getDatabase();
518→    const newMessages = getMessagesDelta(db, sessionId, lastSeq);
519→
520→    if (newMessages.length === 0) return;
521→
522→    const maxSeq = newMessages[newMessages.length - 1].seq;
523→    messageCursors.set(cursorKey, maxSeq);
524→
525→    sendFrame(connectionId, {
526→      type: "q:delta",
527→      id: subId,
528→      upserted: newMessages,
529→      cursor: maxSeq,
530→    });
531→  } catch (err) {
532→    console.error(`[QueryEngine] Message delta push failed:`, err);
533→  }
534→}
